// src/components/common/RoleBasedNav.js
import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useRole } from '../../context/RoleContext';
import PermissionGate from './PermissionGate';
import './RoleBasedNav.css';

const RoleBasedNav = () => {
    const { user, logout } = useAuth();
    const { userRole, isRole } = useRole();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/');
    };

    const getRoleIcon = () => {
        switch(userRole) {
            case 'master_admin':
                return '👑';
            case 'doctor':
                return '👨‍⚕️';
            case 'nurse':
                return '👩‍⚕️';
            default:
                return '👤';
        }
    };

    const getRoleDisplayName = () => {
        switch(userRole) {
            case 'master_admin':
                return 'Master Admin';
            case 'doctor':
                return 'Doctor';
            case 'nurse':
                return 'Nurse';
            default:
                return userRole?.replace('_', ' ').toUpperCase() || 'Patient';
        }
    };

    return (
        <nav className="role-nav">
            <div className="nav-container">
                <div className="nav-brand">
                    <Link to={isRole('master_admin') ? '/admin' : '/dashboard'}>
                        <h2>🏥 E-Health</h2>
                    </Link>
                </div>
                
                <div className="nav-menu">
                    {isRole('master_admin') ? (
                        <>
                            <Link to="/admin" className="nav-link">👑 Admin Dashboard</Link>
                            <Link to="/admin/roles" className="nav-link">⚙️ Manage Roles</Link>
                            <Link to="/admin/verifications" className="nav-link">✅ Verifications</Link>
                            <Link to="/admin" className="nav-link">👥 All Users</Link>
                        </>
                    ) : (
                        <>
                            <Link to="/dashboard" className="nav-link">Dashboard</Link>
                            <PermissionGate permissions={['view_patient_records']}>
                                <Link to="/patients" className="nav-link">Patients</Link>
                            </PermissionGate>
                            <PermissionGate permissions={['view_all_appointments']}>
                                <Link to="/appointments" className="nav-link">Appointments</Link>
                            </PermissionGate>
                            <PermissionGate permissions={['view_all_prescriptions']}>
                                <Link to="/prescriptions" className="nav-link">Prescriptions</Link>
                            </PermissionGate>
                        </>
                    )}
                </div>
                
                <div className="nav-user">
                    <div className="user-info">
                        <span className="user-role-badge" title={getRoleDisplayName()}>
                            {getRoleIcon()}
                        </span>
                        <span className="user-name">{user?.username}</span>
                    </div>
                    <button onClick={handleLogout} className="logout-btn">
                        Logout
                    </button>
                </div>
            </div>
        </nav>
    );
};

export default RoleBasedNav;
